// Loop each draft and prepare LLM scoring request
const threshold = $json.threshold;
const drafts = $input.all()[0]?.json || [];

if (!Array.isArray(drafts) || drafts.length === 0) {
  return [{ json: { message: 'No auto-approve candidates found', drafts_count: 0 } }];
}

const out = [];
for (const draft of drafts) {
  const assetLabel = {
    'caption_social': 'Caption per social media',
    'ad_copy': 'Ad copy commerciale',
    'landing_section': 'Sezione landing page',
    'email_drip': 'Email drip campaign'
  }[draft.asset_type] || draft.asset_type;

  out.push({
    json: {
      draft_id: draft.id,
      workflow: draft.workflow,
      asset_type: draft.asset_type,
      platform: draft.platform,
      lang: draft.lang,
      body: draft.body,
      created_at: draft.created_at,
      asset_label: assetLabel,
      threshold: threshold
    }
  });
}

return out;

