// Parse Gemini response and extract JSON score
// Response format: { "candidates": [{ "content": { "parts": [{ "text": "...json..." }] } }] }

const resp = $json;
let scoreJson = null;

try {
  const candidates = resp.candidates || [];
  if (candidates.length > 0 && candidates[0].content?.parts?.[0]?.text) {
    const text = candidates[0].content.parts[0].text;
    // Extract JSON from text (may have surrounding text)
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      scoreJson = JSON.parse(jsonMatch[0]);
    }
  }
} catch (err) {
  // Parse error, fallback to neutral score
  scoreJson = { total_score: 50, recommendation: 'needs_human', reasoning: 'LLM parse error', escalate_reason: 'gemini_response_parse_failed' };
}

if (!scoreJson) {
  scoreJson = { total_score: 50, recommendation: 'needs_human', reasoning: 'No valid score', escalate_reason: 'gemini_empty_response' };
}

// Merge with input
return [{ json: { ...($input.first().json), score: scoreJson } }];

// Decision branch: auto_approve vs needs_review vs reject
// Inputs: draft_id, threshold, score.total_score, score.recommendation

const draft_id = $json.draft_id;
const score = $json.score.total_score;
const threshold = $json.threshold;
const recommendation = $json.score.recommendation;
const reasoning = $json.score.reasoning;
const escalate_reason = $json.score.escalate_reason;

let decision = 'needs_review';
let newStatus = 'needs_review';

if (score >= threshold && recommendation === 'auto_approve') {
  decision = 'auto_approve';
  newStatus = 'approved';
} else if (score < 70 || recommendation === 'reject') {
  decision = 'reject';
  newStatus = 'rejected';
}

return [{ json: { draft_id, score, threshold, decision, newStatus, reasoning, escalate_reason, recommendation } }];

// Alert Telegram if needs_review (score 70-89) or escalate reason
const decision = $json.decision;
const score = $json.score;
const reasoning = $json.reasoning;
const escalate_reason = $json.escalate_reason;

if (decision === 'needs_review' && !escalate_reason) {
  return [{ json: { send_alert: true, text: `⚠️ Draft #{{ $json.draft_id }} needs human review\nScore: {{ $json.score }}/100\nReason: {{ $json.reasoning }}` } }];
}
if (escalate_reason) {
  return [{ json: { send_alert: true, text: `🚨 Draft #{{ $json.draft_id }} escalation: {{ escalate_reason }}\nScore: {{ $json.score }}` } }];
}

return [{ json: { send_alert: false } }];

// Throttle 2s between LLM requests to stay under Gemini rate limits
await new Promise(resolve => setTimeout(resolve, 2000));
return [{ json: $json }];

// Daily auto_approve_rate metric
// SELECT COUNT(*) as count FROM gemini_copy_drafts WHERE auto_approved=true AND approved_at > NOW() - INTERVAL '1 day'
const today_auto_approves = $input.first().json?.today_auto_approves || 0;
const rate = today_auto_approves;

if (rate < 50 && rate > 0) {
  return [{ json: { metric: 'auto_approve_rate', value: rate, alert: true, text: `⚠️ Auto-approve degraded today: only {{ rate }} approvals. Check LLM quality.` } }];
}

return [{ json: { metric: 'auto_approve_rate', value: rate, alert: false } }];

// Parse /draft-approve: { draft_id, approver, action ('approve'|'reject') }
const body = $json.body || {};
const draft_id = body.draft_id;
const approver = body.approver || 'web-approver';
const action = body.action || 'approve';

if (!draft_id) {
  return [{ json: { ok: false, error: 'Missing draft_id' }, statusCode: 400 }];
}

const newStatus = action === 'reject' ? 'rejected' : 'approved';

return [{ json: { draft_id, approver, action: newStatus } }];

// Parse /draft-list: ?workflow=W20&asset_type=caption&lang=it&status=draft
// Restituisce parametri di filtro (NOT SQL concatenato)
const query = $json.query || {};
const workflow = query.workflow || null;
const asset_type = query.asset_type || null;
const lang = query.lang || null;
const status = query.status || 'draft';
const limit = Math.min(parseInt(query.limit || '20'), 100);
const offset = Math.max(parseInt(query.offset || '0'), 0);

return [{ json: { workflow, asset_type, lang, status, limit, offset } }];

// Parse /draft-bulk-approve: { draft_ids: [1,2,3], approver }
const body = $json.body || {};
const draft_ids = body.draft_ids || [];
const approver = body.approver || 'bulk-approver';

if (!Array.isArray(draft_ids) || draft_ids.length === 0) {
  return [{ json: { ok: false, error: 'Missing or empty draft_ids' }, statusCode: 400 }];
}

return [{ json: { draft_ids, approver, count: draft_ids.length } }];

// Distribuisci approved drafts per asset_type
const items = $input.all();
const byType = {};

for (const it of items) {
  const d = it.json;
  const type = d.asset_type || 'unknown';
  if (!byType[type]) byType[type] = [];
  byType[type].push(d);
}

const out = [];
for (const [type, drafts] of Object.entries(byType)) {
  out.push({ json: { asset_type: type, drafts, count: drafts.length } });
}

return out;

// Distribuisci caption_social -> posts_queue (webhook call)
const group = $json;
if (group.asset_type !== 'caption_social') {
  return [{ json: null }];
}

const out = [];
for (const draft of group.drafts) {
  out.push({
    json: {
      workflow: 'w25-publish',
      asset_type: 'caption_social',
      platform: draft.platform || 'instagram',
      lang: draft.lang || 'it',
      body: draft.body,
      draft_id: draft.id,
      source_workflow: draft.workflow
    }
  });
}

return out;

// Distribuisci altri asset_type -> Telegram notify
const group = $json;
const typeLabel = {
  'email_drip': '📧 Email drip',
  'ad_copy': '📢 Ad copy',
  'landing_section': '🏠 Landing section',
  'marketing_plan': '📋 Marketing plan',
  'seo_brief': '🔍 SEO brief'
}[group.asset_type] || group.asset_type;

const draftList = group.drafts
  .map((d, i) => `  ${i+1}. [ID ${d.id}] ${d.lang} — ${d.workflow}`)
  .join('\n');

const text = `🎯 *${typeLabel}* — ${group.count} draft approved\n\n${draftList}\n\n⚠️ Copia manualmente nel rispettivo sistema.`;

return [{ json: { text, asset_type: group.asset_type } }];

// HMAC-SHA256 Webhook Authentication (inline)
// Validates X-AdOff-Signature header against raw body
// Returns ok:true + extracted payload, or blocks with 401

const crypto = require('crypto');
const secret = process.env.WEBHOOK_HMAC_SECRET;

if (!secret) {
  throw new Error('WEBHOOK_HMAC_SECRET not configured');
}

// Extract signature from headers
const signature = $json.$headers?.['x-adoff-signature'] || $json.headers?.['x-adoff-signature'];
const body = $json.$body || $json.body || JSON.stringify($json);

// In DEV_MODE (env), skip check
if (process.env.DEV_MODE === 'true') {
  return [{ json: { ...($json.body || $json), __hmac_skipped: true } }];
}

if (!signature) {
  return [{ json: { __hmac_error: 'missing_signature_header', statusCode: 401 } }];
}

// Calculate expected HMAC
let bodyForHmac = body;
if (typeof body === 'object') {
  bodyForHmac = JSON.stringify(body);
}

const expectedHmac = crypto
  .createHmac('sha256', Buffer.from(secret, 'hex'))
  .update(bodyForHmac, 'utf8')
  .digest('hex');

// Timing-safe comparison
try {
  crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedHmac, 'hex')
  );
  // Valid signature: continue with payload
  return [{ json: { ...($json.body || $json), __hmac_validated: true } }];
} catch (err) {
  return [{ json: { __hmac_error: 'invalid_signature', statusCode: 401 } }];
}

